/**
 * Loads health check results from /data/health.json (generated by GitHub Actions)
 * and updates the health badges and summary table on the page.
 *
 * The health.json file is written by .github/workflows/health-check.yml and
 * committed back to the repo on each run. Hugo copies it from data/ to public/
 * as a static asset so it's always available at the correct relative URL.
 */
(async () => {
  const summaryEl = document.getElementById("health-summary");
  const detailsEl = document.getElementById("health-details");
  const lastRunEl = document.getElementById("health-last-run");

  let health;
  try {
    const res = await fetch("data/health.json");
    if (!res.ok) throw new Error("not found");
    health = await res.json();
  } catch {
    if (summaryEl) {
      summaryEl.innerHTML = '<span class="health-dot warn"></span> Health data unavailable';
    }
    if (detailsEl) {
      detailsEl.innerHTML = '<p class="loading-msg">Run the health-check workflow to generate status.</p>';
    }
    return;
  }

  const results = health.results || [];
  const runAt = health.run_at ? new Date(health.run_at).toLocaleString() : "unknown";
  if (lastRunEl) lastRunEl.textContent = runAt;

  const ok = results.filter(r => r.status === "ok").length;
  const total = results.length;
  const hasError = results.some(r => r.status === "error");
  const hasWarn = results.some(r => r.status === "warn");

  const summaryClass = hasError ? "error" : hasWarn ? "warn" : "ok";
  const summaryText = hasError
    ? `${total - ok} project${total - ok !== 1 ? "s" : ""} need attention`
    : `All ${ok} projects healthy`;

  if (summaryEl) {
    summaryEl.innerHTML = `<span class="health-dot ${summaryClass}"></span> ${summaryText}`;
  }

  // Update per-project badges
  for (const result of results) {
    const badge = document.querySelector(`.health-badge[data-project="${result.id}"]`);
    if (badge) {
      badge.className = `health-badge ${result.status}`;
      badge.title = result.message || result.status;
    }
  }

  // Build health table
  if (detailsEl && results.length > 0) {
    const rows = results.map(r => {
      const statusClass = r.status === "ok" ? "status-ok" : r.status === "warn" ? "status-warn" : "status-err";
      const icon = r.status === "ok" ? "✓" : r.status === "warn" ? "⚠" : "✗";
      return `<tr>
        <td>${r.name}</td>
        <td class="${statusClass}">${icon} ${r.status.toUpperCase()}</td>
        <td>${r.message || "—"}</td>
        <td>${r.last_commit_age_days != null ? r.last_commit_age_days + "d ago" : "—"}</td>
        <td>${r.open_issues != null ? r.open_issues : "—"}</td>
      </tr>`;
    }).join("");

    detailsEl.innerHTML = `
      <table class="health-table">
        <thead>
          <tr>
            <th>Project</th>
            <th>Status</th>
            <th>Message</th>
            <th>Last Commit</th>
            <th>Open Issues</th>
          </tr>
        </thead>
        <tbody>${rows}</tbody>
      </table>`;
  }
})();
